import React, { useCallback, useMemo, useRef, useState, type ChangeEvent } from "react";
import {
  FlatList,
  Keyboard,
  Pressable,
  View,
  StyleSheet, Text, TextInput
} from "react-native";
import { Input, InputField, type VirtualScrollerOptions } from "../../";
import type {ListRenderItem} from "@react-native/virtualized-lists";
import { resolveThemeTokenForNative } from '../../Factory/helpers/style';

/* ---------------------------------------------
 Types (PrimeReact-compatible)
---------------------------------------------- */

export interface DropdownChangeEvent<T = any> {
  originalEvent?: any;
  value: T | null;
}


export interface DropdownProps<T = any> {
  value?: T | null;
  options?: T[];

  onChange?: (e: ChangeEvent<T>, item:any) => void;

  optionLabel?: string;
  optionValue?: string;

  placeholder?: string;
  disabled?: boolean;
  editable?: boolean;
  loading?: boolean;
  showClear?: boolean;

  checkmark?: boolean;
  highlightOnSelect?: boolean;

  filter?: boolean;
  filterBy?: string;
  emptyFilterMessage?: string;

  itemTemplate?: (item: T) => React.ReactNode;
  valueTemplate?: (value: T | null) => React.ReactNode;
  panelFooterTemplate?: () => React.ReactNode;

  optionGroupLabel?: string;
  optionGroupChildren?: string;
  optionGroupTemplate?: (group: any) => React.ReactNode;

  virtualScrollerOptions?: VirtualScrollerOptions;

  invalid?: boolean;
  testID?: string;
  style?: import('react-native').ViewStyle;
}

/* ---------------------------------------------
 Helpers
---------------------------------------------- */

const getLabel = (item: any, optionLabel?: string) => {
  if (!item) return "";
  if (!optionLabel) return String(item);
  return String(item[optionLabel]);
};

const getValue = (item: any, optionValue?: string) => {
  if (!item) return null;
  if (!optionValue) return item;
  return item[optionValue];
};

const t = resolveThemeTokenForNative;

const TEXT_STYLE_KEYS = new Set([
  'fontSize', 'fontFamily', 'fontWeight', 'fontStyle',
  'color', 'letterSpacing', 'lineHeight', 'textAlign',
  'textDecorationLine', 'textTransform',
]);

function splitStyle(combined?: any): { viewStyle?: any; textStyle?: any } {
  if (!combined) return {};
  const view: Record<string, any> = {};
  const text: Record<string, any> = {};
  for (const [k, v] of Object.entries(combined)) {
    if (TEXT_STYLE_KEYS.has(k)) text[k] = v;
    else view[k] = v;
  }
  return {
    viewStyle: Object.keys(view).length ? view : undefined,
    textStyle: Object.keys(text).length ? text : undefined,
  };
}

/* ---------------------------------------------
 Component
---------------------------------------------- */

export default function Dropdown<T = any>({
                                    value,
                                    options = [],
                                    onChange,

                                    optionLabel,
                                    optionValue,

                                    placeholder,
                                    disabled,
                                    editable,

                                    checkmark,
                                    highlightOnSelect = true,

                                    filter,
                                    filterBy,
                                    emptyFilterMessage = 'No results found',

                                    itemTemplate,
                                    valueTemplate,
                                    panelFooterTemplate,

                                    optionGroupLabel,
                                    optionGroupChildren,
                                    optionGroupTemplate,

                                    virtualScrollerOptions,

                                    invalid,
                                    testID,
                                    style: externalStyle,
                                  }: DropdownProps<T>) {
  const inputRef = useRef<any>(null);
  const [open, setOpen] = useState(false);
  const [inputText, setInputText] = useState("");
  const [filterQuery, setFilterQuery] = useState("");

  const { viewStyle: externalViewStyle, textStyle: externalTextStyle } = splitStyle(externalStyle);

  const colors = {
    border: t('border') || t('gray.300'),
    borderInvalid: t('danger') || t('red.500'),
    bg: t('surface-card') || '#fff',
    text: t('text') || t('gray.800'),
    placeholder: t('text-secondary') || t('gray.400'),
    optionSelected: t('highlight-bg') || t('gray.100'),
    groupBg: t('surface-ground') || t('gray.50'),
    filterBorder: t('border') || t('gray.200'),
    filterBg: t('surface-ground') || t('gray.50'),
    filterText: t('text') || t('gray.800'),
    emptyText: t('text-secondary') || t('gray.400'),
    primary: t('primary'),
  };

  /* ---------------------------------------------
   Derived
  ---------------------------------------------- */

  const selectedItem = useMemo(() => {
    if (value == null) return null;
    // Search through group children when grouped
    if (optionGroupChildren) {
      for (const group of options as any[]) {
        const children = group[optionGroupChildren];
        if (Array.isArray(children)) {
          const found = children.find((c: any) => getValue(c, optionValue) === value);
          if (found) return found;
        }
      }
      return null;
    }
    return options.find(
      (o) => getValue(o, optionValue) === value
    ) ?? null;
  }, [value, options, optionValue, optionGroupChildren]);

  /* ---------------------------------------------
   Open / Close
  ---------------------------------------------- */

  const toggle = () => {
    if (disabled) return;
    setOpen((o) => {
      if (!o) setFilterQuery(""); // reset filter on open
      return !o;
    });
    Keyboard.dismiss();
  };

  const close = () => setOpen(false);

  /* ---------------------------------------------
   Selection
  ---------------------------------------------- */

  const selectItem = (item: T) => {
    const newValue = getValue(item, optionValue);

    if (!onChange) return;

    const syntheticEvent = {
      target: {
        value: newValue,
      },
    } as React.ChangeEvent<any>;

    onChange(syntheticEvent, item);

    setOpen(false);
  };

  /* ---------------------------------------------
   Render item
  ---------------------------------------------- */

  const renderItem: ListRenderItem<any> = useCallback(
    ({ item }) => {
      if (!item) {
        return null;
      }

      // Group header
      if (item.__group) {
        return (
          <Text style={[styles.groupLabel, { backgroundColor: colors.groupBg }]}>
            {optionGroupLabel ? item.group?.[optionGroupLabel] : ""}
          </Text>
        );
      }

      const selected =
        value != null &&
        getValue(item, optionValue) === value;

      let content: React.ReactElement;

      if (itemTemplate) {
        const rendered = itemTemplate(item);

        content = React.isValidElement(rendered) ? (
          rendered
        ) : (
          <Text>{String(rendered ?? "")}</Text>
        );
      } else {
        content = (
          <Text style={[{ color: colors.text }, externalTextStyle && { fontSize: externalTextStyle.fontSize }]}>
            {getLabel(item, optionLabel)}
          </Text>
        );
      }

      return (
        <Pressable
          onPress={() => selectItem(item)}
          style={[
            styles.option,
            selected && highlightOnSelect && { backgroundColor: colors.optionSelected },
          ]}
        >
          {content}
          {checkmark && selected && <Text>✓</Text>}
        </Pressable>
      );
    },
    [
      value,
      optionValue,
      optionLabel,
      itemTemplate,
      optionGroupLabel,
      checkmark,
      highlightOnSelect,
    ]
  );


  /* ---------------------------------------------
   Group flattening
  ---------------------------------------------- */

  const flatData = useMemo(() => {
    if (!optionGroupLabel || !optionGroupChildren) {
      return options;
    }

    const out: any[] = [];
    options.forEach((g: any) => {
      out.push({ __group: true, group: g });
      g[optionGroupChildren]?.forEach((c: any) => out.push(c));
    });
    return out;
  }, [options]);

  /* ---------------------------------------------
   Filter
  ---------------------------------------------- */

  const filteredData = useMemo(() => {
    if (!filter || !filterQuery) return flatData;
    const q = filterQuery.toLowerCase();
    const key = filterBy || optionLabel;

    return flatData.filter((entry: any) => {
      // Keep group headers
      if (entry.__group) return true;
      const label = getLabel(entry, key);
      return label.toLowerCase().includes(q);
    });
  }, [flatData, filter, filterQuery, filterBy, optionLabel]);

  /* ---------------------------------------------
   Display value
  ---------------------------------------------- */

  const displayValue = valueTemplate
    ? valueTemplate(selectedItem)
    : selectedItem
      ? getLabel(selectedItem, optionLabel)
      : "";

  /* ---------------------------------------------
   Render
  ---------------------------------------------- */

  return (
    <View style={styles.container} testID={testID}>
      <Pressable
        style={[
          styles.control,
          { borderColor: colors.border, backgroundColor: colors.bg },
          invalid && { borderColor: colors.borderInvalid },
          disabled && styles.disabled,
          externalViewStyle,
        ]}
        onPress={toggle}
      >
        {editable ? (
          <Input style={styles.input}>
            <InputField
              ref={inputRef}
              value={inputText}
              onChangeText={setInputText}
              placeholder={placeholder}
              editable={!disabled}
            />
          </Input>
        ) : (
          <Text style={[
            displayValue ? { color: colors.text } : { color: colors.placeholder },
            externalTextStyle,
            !displayValue && { color: colors.placeholder },
          ]}>
            {displayValue || placeholder}
          </Text>
        )}

        <Text style={[{ color: colors.text }, externalTextStyle]}>▾</Text>
      </Pressable>

      {open && (
        <View style={[styles.panel, { borderColor: colors.border, backgroundColor: colors.bg }]}>
          {filter && (
            <View style={[styles.filterContainer, { borderBottomColor: colors.filterBorder }]}>
              <TextInput
                value={filterQuery}
                onChangeText={setFilterQuery}
                placeholder="Search..."
                placeholderTextColor={colors.placeholder}
                style={[styles.filterInput, {
                  borderColor: colors.filterBorder,
                  backgroundColor: colors.filterBg,
                  color: colors.filterText,
                }]}
                autoFocus
              />
            </View>
          )}
          <FlatList
            data={filteredData}
            keyExtractor={(_, i) => String(i)}
            renderItem={renderItem}
            keyboardShouldPersistTaps="handled"
            ListEmptyComponent={
              filterQuery ? (
                <View style={styles.emptyContainer}>
                  <Text style={[styles.emptyText, { color: colors.emptyText }]}>{emptyFilterMessage}</Text>
                </View>
              ) : null
            }
            getItemLayout={
              virtualScrollerOptions
                ? (_, index) => ({
                  length: virtualScrollerOptions.itemSize,
                  offset:
                    virtualScrollerOptions.itemSize * index,
                  index,
                })
                : undefined
            }
          />
          {panelFooterTemplate?.()}
        </View>
      )}
    </View>
  );
}

/* ---------------------------------------------
 Styles (layout only — colors applied inline via theme tokens)
---------------------------------------------- */

const styles = StyleSheet.create({
  container: {
    width: "100%",
    position: "relative" as const,
  },
  control: {
    flexDirection: "row" as const,
    alignItems: "center" as const,
    justifyContent: "space-between" as const,
    borderWidth: 1,
    borderRadius: 6,
    paddingHorizontal: 10,
    paddingVertical: 10,
  },
  disabled: {
    opacity: 0.5,
  },
  option: {
    paddingHorizontal: 12,
    paddingVertical: 10,
    flexDirection: "row" as const,
    justifyContent: "space-between" as const,
    alignItems: "center" as const,
  },
  groupLabel: {
    paddingHorizontal: 12,
    paddingVertical: 8,
    fontWeight: "600" as const,
  },
  input: {
    flex: 1,
  },
  panel: {
    position: "absolute" as const,
    top: "100%",
    left: 0,
    right: 0,
    marginTop: 4,
    borderWidth: 1,
    borderRadius: 6,
    maxHeight: 260,
    zIndex: 9999,
  },
  filterContainer: {
    paddingHorizontal: 8,
    paddingVertical: 6,
    borderBottomWidth: 1,
  },
  filterInput: {
    fontSize: 14,
    paddingHorizontal: 8,
    paddingVertical: 6,
    borderWidth: 1,
    borderRadius: 4,
  },
  emptyContainer: {
    padding: 16,
    alignItems: 'center' as const,
  },
  emptyText: {
    fontSize: 14,
  },
});
